// =============================
// Executive KPI Engine
// =============================

// Read executed node outputs
const supplier = $("Get Supplier Risk Report").all().map(i => i.json);
const procurement = $("Get Procurement Report").all().map(i => i.json);
const warehouse = $("Get Warehouse Report").all().map(i => i.json);
const demand = $("Get Demand Report").all().map(i => i.json);
const logistics = $("Get Logistics Report").all().map(i => i.json);

// -----------------------------
// Supplier KPIs
// -----------------------------
const totalSuppliers = supplier.length;

const highRiskSuppliers = supplier.filter(r =>
["High","Very High","Critical"].includes(r.Supplier_Risk)
).length;

// -----------------------------
// Procurement KPIs
// -----------------------------
const openOrders = procurement.filter(r =>
["Open","Pending"].includes(r.Procurement_Status)
).length;

const emergencyOrders = procurement.filter(r =>
["Critical","Emergency"].includes(r.Purchase_Priority)
).length;

// -----------------------------
// Warehouse KPIs
// -----------------------------
const criticalInventory = warehouse.filter(r =>
r.Risk_Level === "Critical"
).length;

const inventoryValueAtRisk = warehouse
.filter(r => ["Critical","High"].includes(r.Risk_Level))
.reduce((sum,row)=>sum+Number(row.Inventory_Value_USD||0),0);

// -----------------------------
// Demand KPIs
// -----------------------------
const forecastRisk = demand.filter(r =>
["High","Critical"].includes(r.Forecast_Risk)
).length;

// -----------------------------
// Logistics KPIs
// -----------------------------
const criticalShipments = logistics.filter(r =>
r.Transportation_Risk==="Critical"
).length;

const avgLogisticsHealth =
logistics.reduce((sum,row)=>
sum+Number(row.Logistics_Health_Score||0),0)
/Math.max(logistics.length,1);

// ======================================================
// OVERALL SUPPLY CHAIN HEALTH (Balanced Score)
// ======================================================

let supplierScore = Math.max(0,100-(highRiskSuppliers*10));

let procurementScore = Math.max(0,100-(emergencyOrders*3 + openOrders*2));

let warehouseScore = Math.max(0,100-(criticalInventory*15));

let demandScore = Math.max(0,100-(forecastRisk*2));

let logisticsScore = avgLogisticsHealth;

// Weighted Average
let health = (
supplierScore*0.20 +
procurementScore*0.20 +
warehouseScore*0.20 +
demandScore*0.20 +
logisticsScore*0.20
);

health = Number(Math.max(0,Math.min(100,health)).toFixed(1));

// -----------------------------
// Business Status
// -----------------------------

let status="";
let priority="";
let recommendation="";

if(health>=85){
status="Excellent";
priority="Low";
recommendation="Supply chain is performing efficiently. Continue monitoring KPIs.";
}
else if(health>=70){
status="Healthy";
priority="Medium";
recommendation="Minor operational improvements recommended.";
}
else if(health>=55){
status="Warning";
priority="High";
recommendation="Review supplier performance, procurement delays and logistics risks.";
}
else if(health>=40){
status="High Risk";
priority="Critical";
recommendation="Executive review required. Expedite procurement and transportation immediately.";
}
else{
status="Critical";
priority="Critical";
recommendation="Immediate executive intervention required. Activate contingency plans and prioritize critical shipments.";
}

// -----------------------------
// Output
// -----------------------------

return [{
json:{

Report_Date:new Date().toLocaleDateString(),

Total_Suppliers:totalSuppliers,

High_Risk_Suppliers:highRiskSuppliers,

Open_Procurement_Orders:openOrders,

Emergency_Orders:emergencyOrders,

Critical_Inventory_Items:criticalInventory,

High_Forecast_Risk_Items:forecastRisk,

Critical_Shipments:criticalShipments,

Inventory_Value_At_Risk:Number(inventoryValueAtRisk.toFixed(2)),

Average_Logistics_Health:Number(avgLogisticsHealth.toFixed(1)),

Overall_Supply_Chain_Health:health,

Business_Status:status,

Executive_Priority:priority,

Executive_Recommendation:recommendation

}
}];

const item = $json;

const health = Number(item.Overall_Supply_Chain_Health);

const suppliers = Number(item.High_Risk_Suppliers);

const emergency = Number(item.Emergency_Orders);

const inventory = Number(item.Critical_Inventory_Items);

const shipments = Number(item.Critical_Shipments);

let executiveLevel = "";
let topPriority = "";
let executiveAction = "";
let budgetImpact = "";
let escalation = "";
let nextReview = "";

// ===================================
// Executive Decision Logic
// ===================================

if (health < 40) {

    executiveLevel = "Critical";

    topPriority = "Business Continuity";

    executiveAction =
        "Activate emergency supply chain response. Expedite procurement, transportation and inventory allocation.";

    budgetImpact = "Very High";

    escalation = "CEO & Supply Chain Director";

    nextReview = "Every 2 Hours";

}

else if (health < 60) {

    executiveLevel = "High";

    topPriority = "Risk Mitigation";

    executiveAction =
        "Prioritize high-risk suppliers, accelerate logistics and stabilize inventory.";

    budgetImpact = "High";

    escalation = "Supply Chain Director";

    nextReview = "Daily";

}

else if (health < 80) {

    executiveLevel = "Medium";

    topPriority = "Performance Optimization";

    executiveAction =
        "Monitor procurement and logistics performance. Improve forecast accuracy.";

    budgetImpact = "Medium";

    escalation = "Operations Manager";

    nextReview = "Weekly";

}

else {

    executiveLevel = "Low";

    topPriority = "Continuous Improvement";

    executiveAction =
        "Maintain current supply chain strategy and monitor KPIs.";

    budgetImpact = "Low";

    escalation = "No Escalation";

    nextReview = "Monthly";

}

// ===================================
// Additional Recommendations
// ===================================

let recommendations = [];

if (suppliers > 3)
    recommendations.push("Review high-risk suppliers.");

if (emergency > 10)
    recommendations.push("Approve emergency procurement.");

if (inventory > 5)
    recommendations.push("Increase safety stock.");

if (shipments > 10)
    recommendations.push("Expedite critical shipments.");

// ===================================
// Output
// ===================================

item.Executive_Level = executiveLevel;
item.Top_Priority = topPriority;
item.Executive_Action = executiveAction;
item.Budget_Impact = budgetImpact;
item.Escalation_Level = escalation;
item.Next_Review = nextReview;
item.Strategic_Recommendations =
recommendations.join(" ");

return { json: item };

const item = $json;

const health = item.Overall_Supply_Chain_Health;
const suppliers = item.High_Risk_Suppliers;
const emergency = item.Emergency_Orders;
const inventory = item.Critical_Inventory_Items;
const forecast = item.High_Forecast_Risk_Items;
const shipments = item.Critical_Shipments;

const level = item.Executive_Level;
const priority = item.Top_Priority;
const action = item.Executive_Action;

let summary = "";

// =====================================
// Executive Summary
// =====================================

summary += `Overall Supply Chain Health is ${health}%. `;

summary += `The organization currently has ${suppliers} high-risk suppliers, `;

summary += `${emergency} emergency procurement orders, `;

summary += `${inventory} critical inventory items, `;

summary += `${forecast} high forecast risk products, `;

summary += `and ${shipments} critical logistics shipments. `;

summary += `The overall executive risk level is ${level}. `;

summary += `Top management priority is ${priority}. `;

summary += `Recommended executive action: ${action}`;

// =====================================
// Executive Alerts
// =====================================

let alert = "";

if(level === "Critical"){

alert =
"🔴 CRITICAL ALERT: Immediate executive intervention required.";

}

else if(level === "High"){

alert =
"🟠 HIGH ALERT: Management attention required.";

}

else if(level === "Medium"){

alert =
"🟡 MEDIUM ALERT: Monitor operational performance.";

}

else{

alert =
"🟢 LOW ALERT: Supply chain operating within acceptable limits.";

}

// =====================================
// Output
// =====================================

item.Executive_AI_Summary = summary;

item.Executive_Alert = alert;

return {
json:item
};
